+fn try_store_orthonormal_column(
+    u: &mut [f64],
+    m: usize,
+    col: usize,
+    candidate: &mut [f64],
+    tol: f64,
+) -> bool {
+    for prev in 0..col {
+        let mut dot = 0.0;
+        for row in 0..m {
+            dot += candidate[row] * u[row * m + prev];
+        }
+        for row in 0..m {
+            candidate[row] -= dot * u[row * m + prev];
+        }
+    }
+
+    let norm = candidate
+        .iter()
+        .map(|value| value * value)
+        .sum::<f64>()
+        .sqrt();
+    if !norm.is_finite() || norm <= tol {
+        return false;
+    }
+
+    for row in 0..m {
+        u[row * m + col] = candidate[row] / norm;
+    }
+    true
