+fn store_orthonormal_column(
+    u: &mut [f64],
+    m: usize,
+    col: usize,
+    seed: &[f64],
+    tol: f64,
+) -> Result<(), LinAlgError> {
+    let mut candidate = seed.to_vec();
+    if try_store_orthonormal_column(u, m, col, &mut candidate, tol) {
+        return Ok(());
+    }
+
+    for basis in 0..m {
+        candidate.fill(0.0);
+        candidate[basis] = 1.0;
+        if try_store_orthonormal_column(u, m, col, &mut candidate, tol) {
+            return Ok(());
+        }
+    }
+
+    Err(LinAlgError::SvdNonConvergence)
+}
