+    let a_norm = a.iter().map(|value| value * value).sum::<f64>().sqrt();
+    let ortho_tol = f64::EPSILON * (m as f64) * a_norm.max(1.0) * a_norm.max(1.0) * 16.0;
+    let mut converged = false;
+    for _sweep in 0..SVD_QR_ITERATION_COEFF {
