+                let mut beta = 0.0;
+                let mut gamma = 0.0;
+                for row in 0..m {
+                    let bp = b[row * n + p];
+                    let bq = b[row * n + q];
+                    alpha += bp * bp;
+                    beta += bq * bq;
+                    gamma += bp * bq;
+                }
+
+                if gamma.abs() <= ortho_tol.max(f64::EPSILON * (alpha * beta).sqrt()) {
+                    continue;
+                }
+
+                changed = true;
+                let zeta = (beta - alpha) / (2.0 * gamma);
+                let t = if zeta == 0.0 {
+                    1.0
+                } else {
+                    zeta.signum() / (zeta.abs() + (1.0 + zeta * zeta).sqrt())
+                };
